module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
// Fall back to identity if an older app build doesn't pass resolve().
const R = (typeof resolve === 'function') ? resolve : (p) => p;
const src = (args.src || '').trim();
const trigger = String(args.trigger || 'click').toLowerCase() === 'auto' ? 'auto' : 'click';
const loop = String(args.loop) === 'true';
const muted = String(args.muted) === 'true';
const controls = String(args.controls) === 'true';
let width = parseFloat(args.width); if (!Number.isFinite(width) || width <= 0) width = 480;

if (!src) return '\n\n<div class="mdp-mod-video mdp-video-empty">（@video: src に動画ファイルのパスか YouTube URL を指定）</div>\n\n';

const yt = src.match(/(?:youtube\.com\/(?:watch\?v=|embed\/|shorts\/)|youtu\.be\/)([A-Za-z0-9_-]{6,})/);
let inner, kind;
if (yt) {
  kind = 'yt';
  const id = yt[1];
  const p = ['enablejsapi=1', 'playsinline=1', 'rel=0', 'modestbranding=1'];
  if (trigger === 'auto') p.push('autoplay=1');
  if (muted || trigger === 'auto') p.push('mute=1');
  if (loop) p.push('loop=1', 'playlist=' + id);
  p.push('controls=' + (controls ? '1' : '0'));
  const url = 'https://www.youtube.com/embed/' + id + '?' + p.join('&');
  inner = '<iframe class="mdp-video-frame" src="' + esc(url) + '" frameborder="0" allow="autoplay; encrypted-media; picture-in-picture; fullscreen" allowfullscreen></iframe>';
} else {
  kind = 'file';
  const attrs = ['class="mdp-video-el"', 'playsinline', 'preload="auto"'];
  if (controls) attrs.push('controls');
  if (loop) attrs.push('loop');
  if (muted) attrs.push('muted');
  // resolve() (provided by the app) maps a deck-relative path / @alias / URL to a
  // served URL, so the <video> can load a local file directly.
  inner = '<video ' + attrs.join(' ') + ' src="' + esc(R(src)) + '"></video>';
}
const overlay = (kind === 'yt' ? (trigger === 'click') : !controls)
  ? '<div class="mdp-video-play" aria-hidden="true"><div class="mdp-video-play-btn">▶</div></div>'
  : '';

return '\n\n<div class="mdp-mod-video mdp-interactive" data-kind="' + kind + '" data-trigger="' + trigger + '" data-controls="' + (controls ? '1' : '0') + '" style="--vid-w:' + width + 'px;">' + inner + overlay + '</div>\n\n';

module.script:
export default {
  init(el, ctx) {
    const trigger = el.dataset.trigger === 'auto' ? 'auto' : 'click';
    const controls = el.dataset.controls === '1';
    const overlay = el.querySelector('.mdp-video-play');
    const showOv = () => { if (overlay) overlay.style.display = 'flex'; };
    const hideOv = () => { if (overlay) overlay.style.display = 'none'; };
    const video = el.querySelector('video');

    if (video) {
      const tryPlay = () => {
        const p = video.play();
        if (p && typeof p.then === 'function') {
          p.then(hideOv).catch(() => {
            // Autoplay with sound blocked → retry muted.
            video.muted = true;
            const q = video.play();
            if (q && typeof q.then === 'function') q.then(hideOv).catch(showOv);
          });
        } else { hideOv(); }
      };
      const toggle = (e) => {
        if (e) e.stopPropagation();
        if (video.paused) tryPlay(); else video.pause();
      };
      if (!controls) {
        el.addEventListener('click', toggle);
        video.addEventListener('play', hideOv);
        video.addEventListener('pause', showOv);
        video.addEventListener('ended', showOv);
      }
      if (trigger === 'auto') tryPlay();
      else if (!controls) showOv();
      ctx.onCleanup(() => {
        if (!controls) el.removeEventListener('click', toggle);
        try { video.pause(); video.currentTime = 0; } catch (e) {}
      });
    } else {
      const iframe = el.querySelector('iframe');
      const post = (func) => {
        try { if (iframe && iframe.contentWindow) iframe.contentWindow.postMessage(JSON.stringify({ event: 'command', func: func, args: [] }), '*'); } catch (e) {}
      };
      if (trigger === 'click' && overlay) {
        showOv();
        overlay.addEventListener('click', (e) => { e.stopPropagation(); hideOv(); post('playVideo'); });
      } else {
        hideOv();
      }
      ctx.onCleanup(() => { post('pauseVideo'); });
    }
  }
}
